        // No silent failures (mirrors UIView.ProcessCommand): warn when an id matches no
        // registered control — its catalog presenter hasn't loaded or the id is wrong.
        private static void BindSetting<T>(string category, string name, Action<T> setter)
        {
            if (UserSettingsService.GetDefinition(category, name) == null)
                Debug.LogWarning($"[Bindings] No settings/cheat control '{category}/{name}' is registered " +
                                 "— bind it after the catalog presenter loads (Start), or fix the id.");
            UserSettingsService.Bind<T>(category, name, null, setter);
        }

